PRAGMA defer_foreign_keys=TRUE;
CREATE TABLE d1_legislators (
  personid INTEGER PRIMARY KEY,
  employeeno INTEGER,
  firstname TEXT,
  lastname TEXT,
  middlename TEXT,
  legislativebody TEXT,
  active INTEGER,
  seatno TEXT,
  countycode TEXT,
  district TEXT,
  party TEXT,
  address TEXT,
  address2 TEXT,
  city TEXT,
  zipcode TEXT,
  emailaddress TEXT,
  gendercode TEXT,
  secretaryid INTEGER,
  database_name TEXT
);
